"use strict";
function asArray(value) { return Array.isArray(value) ? value : value == null ? [] : [value]; }
function normalizeExtension(value = {}) { const manifest = value.manifest || value; const id = String(value.id || value.uuid || manifest.id || manifest.name || ""); return { id, uuid: value.uuid || id, manifest: { ...manifest }, source: value.source || "registry", versions: asArray(value.versions) }; }
function normalizeVersion(value = {}) { return { version: String(value.version || value.tag || "latest"), ...value }; }
function emptyMarketplaceList() { return { extensions: [], items: [], nextPage: null }; }
function createExtensionUrl(baseUrl, ...parts) { const base = String(baseUrl || "").replace(/\/+$/, ""); const suffix = parts.filter(Boolean).map((part) => encodeURIComponent(String(part))).join("/"); return suffix ? `${base}/${suffix}` : base; }
function parseDxtReference(input) { const value = String(input || ""); const [idPart, version] = value.split("@"); const [publisher, name] = idPart.includes("/") ? idPart.split("/", 2) : [undefined, idPart]; return { publisher, name, id: idPart, version: version || undefined }; }
function createMemoryRegistry(initial = []) { const entries = new Map(); for (const entry of initial) { const normalized = normalizeExtension(entry); if (normalized.id) entries.set(normalized.id, normalized); } return { list: () => Array.from(entries.values()), search(query = "") { const needle = String(query).toLowerCase(); return Array.from(entries.values()).filter((entry) => JSON.stringify(entry).toLowerCase().includes(needle)); }, get: (id) => entries.get(String(id)) || null, add(entry) { const normalized = normalizeExtension(entry); entries.set(normalized.id, normalized); return normalized; }, remove: (id) => entries.delete(String(id)), versions: (id) => asArray(entries.get(String(id))?.versions).map(normalizeVersion) }; }
async function fetchJson(url, options) { const response = await fetch(url, options); if (!response.ok) throw new Error(`DXT registry request failed ${response.status}: ${url}`); return response.json(); }
async function listExtensions(source = emptyMarketplaceList()) { if (typeof source === "string") return fetchJson(createExtensionUrl(source, "extensions")); if (source.list) return { extensions: source.list(), items: source.list(), nextPage: null }; return source; }
async function getExtension(source, id) { if (typeof source === "string") return fetchJson(createExtensionUrl(source, "extensions", id)); return source.get ? source.get(id) : null; }
async function listExtensionVersions(source, id) { if (typeof source === "string") return fetchJson(createExtensionUrl(source, "extensions", id, "versions")); return source.versions ? source.versions(id) : []; }
async function getExtensionVersion(source, id, version) { return asArray(await listExtensionVersions(source, id)).map(normalizeVersion).find((entry) => entry.version === version) || null; }
module.exports = { normalizeExtension, normalizeVersion, emptyMarketplaceList, createExtensionUrl, parseDxtReference, createMemoryRegistry, fetchJson, listExtensions, getExtension, listExtensionVersions, getExtensionVersion };
module.exports.default = module.exports;
